const FiltersStory = () => {
    const [appliedFilters, setAppliedFilters] = useState<AppliedFilter[]>([])

    useEffect(() => {
      console.log({ appliedFilters })
    }, [appliedFilters])

    return (
        <div style={{ position: 'relative' }}>
            <Filters
                items={Array(10)
                  .fill(1)
                  .map<Filter>((_v, index) => {
                    const i = index + 1

                    if (index === 0) {
                      return {
                        label: 'Personagem de Star Wars',
                        name: 'star_wars_person',
                        allowEmptySearch: true,
                        delimiter: true,
                        options: async (search, page) => {
                          const responseData = await getStarWars(search, page)

                          // setando se a pagina atual e a ultima
                          const lastPage = !responseData.next
                          // pegando os resultados da requisicao
                          const results = (responseData.results || []) as {
                            name: string
                            url: string
                          }[]

                          return {
                            options: results.map<Option>((e) => ({
                              label: e.name,
                              value: e.url,
                            })),
                            lastPage,
                          }
                        },
                      }
                    }

                    return {
                      label: `Item ${i}`,
                      name: `item_${i}`,
                      options: Array(10)
                        .fill(1)
                        .map((v, index) => {
                          const j = index + 1
                          return {
                            label: `Subtem - ${i}.${j}`,
                            value: j,
                          }
                        }),
                    }
                  })}
                setAppliedFilters={setAppliedFilters} />
        </div>
    );
};

